esqlQuery.esql:
FROM metrics-nginxreceiver.otel-*
// Filter to connection counter documents (exclude gauge docs with state attribute)
| WHERE state IS NULL
// Cast counters to long for aggregation support
| EVAL accepted = TO_LONG(nginx.connections_accepted), handled = TO_LONG(nginx.connections_handled)
// Compute delta over the time window per host
| STATS max_accepted = MAX(accepted), min_accepted = MIN(accepted), max_handled = MAX(handled), min_handled = MIN(handled) BY host.name
// Calculate new connections accepted vs handled in this window
| EVAL delta_accepted = max_accepted - min_accepted, delta_handled = max_handled - min_handled
| EVAL dropped = delta_accepted - delta_handled
// Alert when any connections were dropped
| WHERE dropped > 0
| SORT dropped DESC
| LIMIT 10
